```python
from elasticsearch import Elasticsearch

# Connect and create an index with explicit mapping
es = Elasticsearch('http://localhost:9200')

mapping = {
    'mappings': {
        'properties': {
            'title': {'type': 'text', 'analyzer': 'standard'},
            'price': {'type': 'float'},
            'tags': {'type': 'keyword'},
            'created_at': {'type': 'date'}
        }
    }
}
es.indices.create(index='products', body=mapping)

# Index a document
doc = {'title': 'Wireless Mouse', 'price': 29.99, 'tags': ['electronics', 'peripherals'], 'created_at': '2024-01-15'}
es.index(index='products', id='1', body=doc)

# Search with match query
results = es.search(index='products', body={
    'query': {'match': {'title': 'wireless mouse'}}
})
print(f"Found {results['hits']['total']['value']} documents")
```
